SELECT t0."region" AS "customers__region", SUM(CASE WHEN t1.status = 'cancelled' THEN t1.amount ELSE 0 END) / NULLIF(COUNT(DISTINCT CASE WHEN t1.status = 'cancelled' THEN t1.customer_id END), 0) AS "cancelled_revenue_per_customer" FROM analytics.customers AS t0 LEFT JOIN analytics.orders AS t1 ON t1.customer_id = t0.customer_id GROUP BY t0."region" ORDER BY "customers__region" ASC
